// Auto-generated by scripts/embed_fonts.py
// 两个 Cyrillic+Latin 子集字体内嵌为 base64，避免 supabase functions deploy 不打包二进制资源。
// 大小：Regular ~155KB, Bold ~155KB（base64 后），冷启动直接解码，无 fs 读取。

const REG_B64 = "";

const BOLD_B64 = "";

function decodeBase64(s: string): ArrayBuffer {
  const bin = atob(s);
  const len = bin.length;
  const out = new Uint8Array(len);
  for (let i = 0; i < len; i++) out[i] = bin.charCodeAt(i);
  return out.buffer;
}

export const FONT_REGULAR: ArrayBuffer = decodeBase64(REG_B64);
export const FONT_BOLD: ArrayBuffer = decodeBase64(BOLD_B64);
